import React, { useState } from 'react';
import { View, Text, Button, Alert } from 'react-native';
import * as InAppPurchases from 'react-native-iap';

const items = [
  'com.example.product1',
  'com.example.product2'
];

InAppPurchases.setDebug(true);

const PaymentModule = () => {
  const [products, setProducts] = useState([]);

  const fetchProducts = async () => {
    try {
      await InAppPurchases.requestSubscription(items);
      const products = await InAppPurchases.getProducts(items);
      setProducts(products);
    } catch (error) {
      console.error(error);
    }
  };

  const handlePurchase = async (productId) => {
    try {
      const purchaseResult = await InAppPurchases.requestPurchase(productId);
      if (purchaseResult.transactionState === InAppPurchases.TransactionState.Purchased) {
        Alert.alert('Success', 'Product purchased successfully!');
      }
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <View>
      <Button title="Fetch Products" onPress={fetchProducts} />
      {products.map(product => (
        <View key={product.productId}>
          <Text>{product.title}</Text>
          <Text>{product.description}</Text>
          <Text>${product.price}</Text>
          <Button title="Buy" onPress={() => handlePurchase(product.productId)} />
        </View>
      ))}
    </View>
  );
};

export default PaymentModule;